        heroEffId = heroEffId,
        scale = self._scale,
        side =BattleTeamSide.teamA,
        pos = Vector3(-10,0,0),
        layerName = "ObjectUp",
        parentTran = effTrans,
        onComplete = function()
            if endFunc then
                endFunc()
            end
        end,

    }
    obj:Create(data)



    self._unitMap[key] = obj
    return obj
end


function LBattleViewTreasureMgr:ClearUnits()
    if self._unitMap then
        for k,v in pairs(self._unitMap) do
            v:Destroy()
        end
    end
    self._unitMap = {}
end

